1	import express from 'express';
2	import cors from 'cors';
3	import path from 'path';
4	import { initializeDatabase } from './models/database';
5	import router from './routes';
6	
7	const app = express();
8	const PORT = process.env.PORT || 3000;
9	
10	// Middleware
11	app.use(cors({
12	  origin: process.env.CORS_ORIGIN || '*',
13	  methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH'],
14	  allowedHeaders: ['Content-Type', 'Authorization']
15	}));
16	app.use(express.json({ limit: '10mb' }));
17	app.use(express.urlencoded({ extended: true, limit: '10mb' }));
18	
19	// Serve static files (frontend)
20	app.use(express.static(path.join(__dirname, '../../frontend/public')));
21	
22	// API routes
23	app.use('/api', router);
24	
25	// Health check
26	app.get('/health', (req, res) => {
27	  res.json({ status: 'ok', timestamp: new Date().toISOString(), service: 'Travel Booking API' });
28	});
29	
30	// Fallback for SPA
31	app.get('*', (req, res) => {
32	  if (!req.path.startsWith('/api')) {
33	    res.sendFile(path.join(__dirname, '../../frontend/public/index.html'));
34	  }
35	});
36	
37	// Initialize database and start server
38	initializeDatabase();
39	
40	app.listen(PORT, () => {
41	  console.log(`\n🚀 여행 예약 서버가 실행 중입니다!`);
42	  console.log(`   포트: ${PORT}`);
43	  console.log(`   API: http://localhost:${PORT}/api`);
44	  console.log(`   프론트엔드: http://localhost:${PORT}\n`);
45	});
46	
47	export default app;
48
